import{_ as s,o as t,c as e,a2 as i}from"./chunks/framework.C_Knpfj2.js";const k=JSON.parse('{"title":"Backpressure and Throttling","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/backpressure-and-throttling.md","filePath":"concepts/backpressure-and-throttling.md","lastUpdated":1781454385000}'),l={name:"concepts/backpressure-and-throttling.md"};function n(r,a,o,d,h,c){return t(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="backpressure-and-throttling" tabindex="-1">Backpressure and Throttling <a class="header-anchor" href="#backpressure-and-throttling" aria-label="Permalink to &quot;Backpressure and Throttling&quot;">​</a></h1><p>AOSC controls migration load with cross-shard permits and bulk write controllers.</p><h2 id="cross-shard-backfill-permits" tabindex="-1">Cross-Shard Backfill Permits <a class="header-anchor" href="#cross-shard-backfill-permits" aria-label="Permalink to &quot;Cross-Shard Backfill Permits&quot;">​</a></h2><p><code>aosc.backfill.max_concurrent_per_node</code> limits how many shard workers on a node may hold a backfill permit at the same time.</p><ul><li>Default: <code>10</code></li><li><code>0</code> pauses new backfill work.</li><li>Increasing the setting grants queued workers when capacity is available.</li><li>Decreasing the setting does not revoke already-held permits.</li></ul><h2 id="bulk-write-controllers" tabindex="-1">Bulk Write Controllers <a class="header-anchor" href="#bulk-write-controllers" aria-label="Permalink to &quot;Bulk Write Controllers&quot;">​</a></h2><p>AOSC creates separate bulk writers for backfill and replay.</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Controller</th><th>Backfill</th><th>Replay</th><th>Behavior</th></tr></thead><tbody><tr><td><code>fixed</code></td><td>Yes</td><td>Yes</td><td>Uses configured batch size and fixed concurrency.</td></tr><tr><td><code>adaptive_batch</code></td><td>Yes</td><td>Yes</td><td>Uses fixed concurrency with AIMD batch sizing.</td></tr><tr><td><code>adaptive</code></td><td>Yes</td><td>No</td><td>Uses adaptive batch size and adaptive backfill concurrency.</td></tr></tbody></table></div><h2 id="fixed-mode" tabindex="-1">Fixed Mode <a class="header-anchor" href="#fixed-mode" aria-label="Permalink to &quot;Fixed Mode&quot;">​</a></h2><p>Fixed mode reads current settings dynamically:</p><ul><li><code>aosc.backfill.controller.batch.size</code></li><li><code>aosc.backfill.controller.concurrency</code></li><li><code>aosc.replay.controller.batch.size</code></li></ul><h2 id="adaptive-batch-mode" tabindex="-1">Adaptive Batch Mode <a class="header-anchor" href="#adaptive-batch-mode" aria-label="Permalink to &quot;Adaptive Batch Mode&quot;">​</a></h2><p>Adaptive batch mode adjusts a byte target for each bulk request. It estimates bytes per document and converts the byte target to a document count.</p><p>On overload or transient failures, it reduces the target size. After clean successes, it probes upward within configured bounds.</p><h2 id="adaptive-backfill-mode" tabindex="-1">Adaptive Backfill Mode <a class="header-anchor" href="#adaptive-backfill-mode" aria-label="Permalink to &quot;Adaptive Backfill Mode&quot;">​</a></h2><p>Backfill-only <code>adaptive</code> mode adjusts both batch size and intra-shard write concurrency. It uses latency-gradient signals and overload backoff to reduce pressure when the target slows down.</p><h2 id="operator-tuning" tabindex="-1">Operator Tuning <a class="header-anchor" href="#operator-tuning" aria-label="Permalink to &quot;Operator Tuning&quot;">​</a></h2><p>Slow down backfill:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PUT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;http://localhost:9200/_cluster/settings&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Content-Type: application/json&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;transient&quot;:{&quot;aosc.backfill.max_concurrent_per_node&quot;:2}}&#39;</span></span></code></pre></div><p>Pause new backfill permits:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PUT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;http://localhost:9200/_cluster/settings&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Content-Type: application/json&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;transient&quot;:{&quot;aosc.backfill.max_concurrent_per_node&quot;:0}}&#39;</span></span></code></pre></div><p>Switch backfill to adaptive batch sizing:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PUT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;http://localhost:9200/_cluster/settings&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Content-Type: application/json&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;transient&quot;:{&quot;aosc.backfill.controller.type&quot;:&quot;adaptive_batch&quot;}}&#39;</span></span></code></pre></div><p>Monitor cluster health, indexing pressure, JVM, disk, and bulk rejections while tuning.</p>`,24)])])}const u=s(l,[["render",n]]);export{k as __pageData,u as default};
